mapper.select:
SELECT id, name, color
FROM categories
WHERE id = #{id}

SELECT c.id AS category_id, c.name AS category_name, c.color AS category_color, COUNT(t.id) AS task_count FROM categories c LEFT JOIN todos t ON c.id = t.category_id
AND t.user_id = #{userId}
GROUP BY c.id, c.name, c.color ORDER BY c.id

SELECT t.priority, COUNT(*) AS task_count FROM todos t
t.user_id = #{userId}
GROUP BY t.priority ORDER BY CASE t.priority WHEN 'HIGH' THEN 1 WHEN 'MEDIUM' THEN 2 WHEN 'LOW' THEN 3 ELSE 4 END

SELECT COUNT(*)
FROM todos
WHERE created_at >= #{start}
  AND created_at < #{endExclusive}

SELECT COUNT(*)
FROM todos
WHERE created_at >= #{start}
  AND created_at < #{endExclusive}
  AND completed = TRUE
